const GEMINI_MODEL_PRIMARY = "gemini-3-flash-preview"; 

const scanResultsSchema = {
  type: Type.OBJECT,
  properties: {
    scan_results: {
      type: Type.ARRAY,
      items: {
        type: Type.OBJECT,
        properties: {
          name: { type: Type.STRING },
          code: { type: Type.STRING },
          synergy_score: { type: Type.NUMBER },
          verdict: { type: Type.STRING },
          tomorrow_range: { type: Type.STRING },
          action_hint: { type: Type.STRING }
        },
        required: ["name", "code", "synergy_score", "verdict", "tomorrow_range", "action_hint"]
      }
    },
    battle_summary: { type: Type.STRING }
  },
  required: ["scan_results", "battle_summary"]
};

// ... 原有的 robustParse 保持不变 ...
const robustParse = (text: string): any => {
  if (!text) return null;
  let clean = text.trim();
  clean = clean.replace(/^```[a-z]*\s*/i, '').replace(/^```\s*/i, '').replace(/\s*```$/, '');
  const firstBrace = clean.search(/[{[]/);
  const lastIndex = Math.max(clean.lastIndexOf('}'), clean.lastIndexOf(']'));
  if (firstBrace !== -1 && lastIndex !== -1) clean = clean.substring(firstBrace, lastIndex + 1);
  try {
    return JSON.parse(clean);
  } catch (e) {
    return null;
  }
};

/**
 * 创业板活跃标的合力扫盘
 */
export const fetchChiNextMarketScan = async (apiKey: string): Promise<AnalysisResult> => {
  const ai = new GoogleGenAI({ apiKey });
  const dateStr = new Date().toLocaleDateString('zh-CN');

  const prompt = `
    [强制任务]: 针对 A 股【创业板 (ChiNext)】今日（${dateStr}）的活跃标的进行“合力大师”扫盘打分。

    1. 联网检索：利用 googleSearch 找出今日创业板中【成交额前 20】和【分时显著放量异动】的个股。
    2. 合力测算：对每只个股分析近 3-5 日的 K 线配合度、主力净流入强度。
    3. 输出要求：直接给出一份打分列表，包含个股名称、代码、合力分 (0-100)、明日预期波动区间、极简操盘指令。

    [JSON 结构要求]:
    必须返回一个包含 scan_results 数组的 JSON 对象。
    不要输出多余的文字描述，只要打分列表。
  `;

  const response = await ai.models.generateContent({
    model: GEMINI_MODEL_PRIMARY,
    contents: prompt,
    config: {
      tools: [{ googleSearch: {} }],
      responseMimeType: "application/json",
      responseSchema: scanResultsSchema
    }
  });

  const parsed = robustParse(response.text || "{}");

  return {
    content: response.text || "",
    timestamp: Date.now(),
    modelUsed: ModelProvider.GEMINI_INTL,
    isStructured: true,
    klineSynergyData: parsed,
    market: MarketType.CN
  };
};

// ... 原有的 fetchKLineSynergyAnalysis 等函数保持不变 ...
export const fetchKLineSynergyAnalysis = async (
  query: string,
  base64Image: string | null,
  market: MarketType,
  apiKey: string
): Promise<AnalysisResult> => {
  const ai = new GoogleGenAI({ apiKey });
  const prompt = `分析 ${query} 的3-5日K线合力...`; // 此处保持原有逻辑即可
  const contents: any = { parts: [{ text: prompt }] };
  if (base64Image) {
    contents.parts.push({ inlineData: { mimeType: 'image/jpeg', data: base64Image } });
  }
  const response = await ai.models.generateContent({
    model: GEMINI_MODEL_PRIMARY,
    contents,
    config: { tools: [{ googleSearch: {} }], responseMimeType: "application/json" }
  });
  return {
    content: response.text || "",
    timestamp: Date.now(),
    modelUsed: ModelProvider.GEMINI_INTL,
    isStructured: true,
    klineSynergyData: robustParse(response.text || "{}"),
    market
  };
};

export const fetchGeminiAnalysis = async (prompt: string, isComplex: boolean, apiKey: string): Promise<AnalysisResult> => {
  const ai = new GoogleGenAI({ apiKey });
  const model = isComplex ? "gemini-3-pro-preview" : "gemini-3-flash-preview";
  const response = await ai.models.generateContent({
    model: model,
    contents: prompt,
    config: { tools: [{ googleSearch: {} }] },
  });
  return {
    content: response.text || "",
    groundingSource: response.candidates?.[0]?.groundingMetadata?.groundingChunks?.map((chunk: any) => ({
      uri: chunk.web?.uri || "",
      title: chunk.web?.title || "网页来源"
    })),
    timestamp: Date.now(),
    modelUsed: ModelProvider.GEMINI_INTL
  };
};

