export const extractTradingPlan = async (content: string, apiKey: string): Promise<{ items: PlanItem[], summary: string }> => {
  const ai = new GoogleGenAI({ apiKey });
  const response = await ai.models.generateContent({
    model: GEMINI_MODEL_PRIMARY,
    contents: `提取计划: ${content}`,
    config: { responseMimeType: "application/json" }
  });
  const parsed = robustParse(response.text || "{}");
  return { items: (parsed.items || []).map((item: any) => ({ ...item, id: Math.random().toString(36).substring(7), status: 'pending' })), summary: parsed.summary || "计划" };
};

