  analysisText: string,
  _apiKey: string
): Promise<{ items: PlanItem[], summary: string }> => {
  // Always initialize with the hardcoded named parameter apiKey as per guidelines
  const ai = new GoogleGenAI({ apiKey: process.env.API_KEY });
