      {loading && (
        <div className="py-24 text-center flex flex-col items-center justify-center bg-white rounded-[3rem] border border-dashed border-slate-200 animate-pulse">
          <Fingerprint className="w-16 h-16 text-indigo-300 mb-6" />
          <p className="text-slate-500 font-black text-xl tracking-tight">正在联网穿透全网交易数据，还原主力成本分布...</p>
          <p className="text-slate-300 text-sm mt-3 font-medium">分析引擎正在通过 Google Search 抓取创业板最新龙虎榜与大单动向</p>
