                               />
                            </svg>
                            <div className="absolute flex flex-col items-center">
                               <span className="text-2xl font-black text-slate-800">{stock.control_score}</span>
                               <span className="text-[8px] font-black text-slate-400 uppercase tracking-tighter">控盘分</span>
                            </div>
                         </div>
                         <div>
                            <div className="flex items-center gap-2 mb-1">
                               <h4 className="text-2xl font-black text-slate-800">{stock.name}</h4>
                               <span className="text-xs font-mono text-slate-400 bg-slate-50 px-2 py-0.5 rounded border border-slate-100">{stock.code}</span>
                            </div>
                            <div className="flex items-center gap-2">
                               <span className={`text-[10px] font-black px-2 py-0.5 rounded-lg border uppercase tracking-widest ${
