                               <div className="w-px h-6 bg-slate-100"></div>
                               <div>
                                  <div className="text-[10px] font-black text-slate-400 uppercase">集中度</div>
                                  <div className="text-sm font-black text-slate-800">{stock.chip_concentration}</div>
                               </div>
                            </div>
                         </div>
                      </div>

                      {/* Middle: Costs & Safety Cushion */}
                      <div className="lg:w-1/3 p-8 bg-slate-50/50 flex flex-col justify-center border-r border-slate-100">
                         <div className="space-y-6">
                            <div className="flex justify-between items-center">
                               <div className="flex items-center gap-2">
                                  <div className="p-1.5 bg-indigo-100 rounded-lg text-indigo-600"><DollarSign className="w-4 h-4" /></div>
