                               </div>
                               <span className="text-lg font-black text-slate-900">¥{stock.main_cost}</span>
                            </div>
                            <div className="flex justify-between items-center">
                               <div className="flex items-center gap-2">
                                  <div className="p-1.5 bg-amber-100 rounded-lg text-amber-600"><ShieldCheck className="w-4 h-4" /></div>
                                  <span className="text-sm font-black text-slate-700">当前安全垫</span>
                               </div>
                               <span className={`text-lg font-black ${stock.cost_distance.startsWith('+') ? 'text-rose-600' : 'text-emerald-600'}`}>
                                  {stock.cost_distance}
                               </span>
                            </div>
                            <div className="h-2 bg-slate-200 rounded-full overflow-hidden">
                               <div className="h-full bg-indigo-500 rounded-full" style={{width: `${Math.min(100, (stock.control_score + 20))}%`}}></div>
