                      </div>

                      {/* Right: Battle Verdict & Action */}
                      <div className="lg:w-1/3 p-8 flex flex-col justify-center gap-6">
                         <div className="bg-white p-5 rounded-3xl border border-slate-100 shadow-sm">
                            <div className="text-[10px] font-black text-slate-400 uppercase tracking-[0.2em] mb-3 flex items-center gap-2">
                               <Target className="w-4 h-4 text-rose-500" /> 博弈战法推演
                            </div>
                            <p className="text-sm font-black text-slate-800 leading-relaxed italic">
                               "{stock.battle_verdict}"
                            </p>
                         </div>
                         <button className="w-full h-12 bg-slate-900 hover:bg-slate-800 text-white rounded-2xl font-black shadow-lg transition-all flex items-center justify-center gap-2 group">
                            查看 K 线合力诊断
                            <ArrowRightCircle className="w-4 h-4 group-hover:translate-x-1 transition-transform" />
                         </button>
                      </div>
                   </div>
                </div>
              ))}
           </div>

           <div className="text-center py-10">
              <div className="inline-flex items-center gap-3 px-6 py-3 bg-slate-100 rounded-full text-[10px] text-slate-400 font-black uppercase tracking-[0.3em]">
