import { GoogleGenAI, Type, GenerateContentResponse } from "@google/genai";
import { AnalysisResult, ModelProvider, MarketType, MarketDashboardData, HoldingsSnapshot, PeriodicReviewData, PlanItem, KLineSynergyData, ChipAnalysisData } from "../types";

const GEMINI_MODEL_PRIMARY = "gemini-3-flash-preview"; 

/**
 * 统一获取 GoogleGenAI 实例。
 */
const getAIClient = (apiKey?: string) => {
  const finalKey = apiKey || process.env.API_KEY;
  if (!finalKey) {
    throw new Error("MISSING_API_KEY");
  }
  return new GoogleGenAI({ apiKey: finalKey });
};

// Robust JSON Parser
const robustParse = (text: string): any => {
  if (!text) return null;
  let clean = text.trim();
  clean = clean.replace(/^```[a-z]*\s*/i, '').replace(/^```\s*/i, '').replace(/\s*```$/, '');
  const firstBrace = clean.search(/[{[]/);
  const lastIndex = Math.max(clean.lastIndexOf('}'), clean.lastIndexOf(']'));
  if (firstBrace !== -1 && lastIndex !== -1) clean = clean.substring(firstBrace, lastIndex + 1);
  try {
    return JSON.parse(clean);
  } catch (e) {
    return null;
  }
};

/**
 * 筹码大师：创业板主力监控全景扫描 (批量版)
 */
export const fetchInstitutionalChipAnalysis = async (
  apiKey?: string
): Promise<AnalysisResult> => {
  const ai = getAIClient(apiKey);
  const now = new Date();
  const dateStr = now.toLocaleDateString('zh-CN');

  const chipSchema = {
    type: Type.OBJECT,
    properties: {
      data: {
        type: Type.ARRAY,
        items: {
          type: Type.OBJECT,
          properties: {
            name: { type: Type.STRING },
            code: { type: Type.STRING },
            current_price: { type: Type.STRING },
            control_score: { type: Type.NUMBER },
            control_status: { type: Type.STRING, enum: ["High", "Medium", "Low"] },
            main_cost: { type: Type.STRING },
            cost_distance: { type: Type.STRING },
            profit_ratio: { type: Type.STRING },
            chip_concentration: { type: Type.STRING },
            recent_big_flow: { type: Type.STRING },
            battle_verdict: { type: Type.STRING }
          },
          required: ["name", "code", "control_score", "main_cost", "cost_distance", "battle_verdict"]
        }
      }
    }
  };

  const prompt = `
    [角色]: 你是 A 股顶级量化筹码分析师。
    [任务]: 请利用 googleSearch 实时扫描当前【创业板 (ChiNext)】中成交额最大、涨幅最强势、或龙虎榜异动的【前 20 只】核心标的。
    [要求]:
    1. 必须穿透计算每只标的的【主力控盘度 (0-100分)】。
    2. 必须定位【主力核心成本价】。
    3. 必须计算【安全垫 (Cost Distance)】：当前价与主力成本价的偏离度。
    4. 针对“龙头打板战法”，给出“起爆/锁筹/退潮”等简短结论。
    5. 返回格式必须为 JSON 数组。
    当前日期: ${dateStr}。
  `;

  const response = await ai.models.generateContent({
    model: GEMINI_MODEL_PRIMARY,
    contents: prompt,
    config: {
      tools: [{ googleSearch: {} }],
      responseMimeType: "application/json",
      responseSchema: chipSchema
    }
  });

  const parsed = robustParse(response.text || "{}");

  return {
    content: response.text || "",
    timestamp: Date.now(),
    modelUsed: ModelProvider.GEMINI_INTL,
    isStructured: true,
    chipData: parsed?.data || [],
    market: MarketType.CN
  };
};

/**
 * 保持其他功能完全不变
 */
export const fetchKLineSynergyAnalysis = async (query: string, base64Image: string | null, market: MarketType, apiKey: string): Promise<AnalysisResult> => {
  const ai = getAIClient(apiKey);
  const prompt = `针对 "${query}" 进行 3-5 日 K 线合力分析。输出 JSON。`;
  const contents: any = { parts: [{ text: prompt }] };
  if (base64Image) contents.parts.push({ inlineData: { mimeType: 'image/jpeg', data: base64Image } });
  const response = await ai.models.generateContent({
    model: GEMINI_MODEL_PRIMARY,
    contents,
    config: { tools: [{ googleSearch: {} }], responseMimeType: "application/json" }
  });
  return { content: response.text || "", timestamp: Date.now(), modelUsed: ModelProvider.GEMINI_INTL, isStructured: true, klineSynergyData: robustParse(response.text || "{}"), market };
};

export const fetchGeminiAnalysis = async (prompt: string, isComplex: boolean, apiKey: string): Promise<AnalysisResult> => {
  const ai = getAIClient(apiKey);
  const model = isComplex ? "gemini-3-pro-preview" : "gemini-3-flash-preview";
  const response = await ai.models.generateContent({ model, contents: prompt, config: { tools: [{ googleSearch: {} }] } });
  return { content: response.text || "", groundingSource: response.candidates?.[0]?.groundingMetadata?.groundingChunks?.map((chunk: any) => ({ uri: chunk.web?.uri || "", title: chunk.web?.title || "来源" })), timestamp: Date.now(), modelUsed: ModelProvider.GEMINI_INTL };
};

