export const extractTradingPlan = async (content: string, apiKey: string): Promise<{ items: PlanItem[], summary: string }> => {
  const ai = getAIClient(apiKey);
  const response = await ai.models.generateContent({ model: GEMINI_MODEL_PRIMARY, contents: `提取计划: ${content}`, config: { responseMimeType: "application/json" } });
