import React, { useState, useEffect } from 'react';
import { useNavigate } from 'react-router-dom';
import { ModelProvider, MarketType, AnalysisResult, ChipAnalysisData } from '../types';
import { fetchInstitutionalChipAnalysis } from '../services/geminiService';
import { Fingerprint, Loader2, Search, Zap, Target, AlertTriangle, TrendingUp, Info, Activity, Gauge, BarChart3, ChevronRight, ArrowRightCircle, DollarSign, Wallet, ArrowUpDown, Filter } from 'lucide-react';

interface ChipMasterProps {
  currentModel: ModelProvider;
  currentMarket: MarketType;
  settings: any;
  onOpenSettings: () => void;
}

export const ChipMaster: React.FC<ChipMasterProps> = ({ currentModel, currentMarket, settings, onOpenSettings }) => {
  const navigate = useNavigate();
  const [loading, setLoading] = useState(false);
  const [result, setResult] = useState<AnalysisResult | null>(null);
  const [error, setError] = useState<string | null>(null);
  const [elapsed, setElapsed] = useState(0);

  // 排序与搜索状态
  const [searchTerm, setSearchTerm] = useState('');
  const [sortConfig, setSortConfig] = useState<{ key: keyof ChipAnalysisData; direction: 'asc' | 'desc' } | null>({
    key: 'control_score',
    direction: 'desc'
  });

  useEffect(() => {
    let interval: any;
    if (loading) {
      setElapsed(0);
      interval = setInterval(() => setElapsed(p => p + 1), 1000);
    }
    return () => clearInterval(interval);
  }, [loading]);

  const handleScan = async () => {
    setLoading(true);
    setError(null);
    setResult(null);
    try {
      const data = await fetchInstitutionalChipAnalysis(settings.geminiKey);
      setResult(data);
    } catch (err: any) {
      if (err.message === "MISSING_API_KEY") {
        onOpenSettings();
      } else {
        setError(err.message || "筹码扫描失败，请稍后重试。");
      }
    } finally {
      setLoading(false);
    }
  };

  const handleSort = (key: keyof ChipAnalysisData) => {
    let direction: 'asc' | 'desc' = 'desc';
    if (sortConfig && sortConfig.key === key && sortConfig.direction === 'desc') {
      direction = 'asc';
    }
    setSortConfig({ key, direction });
  };

  const handleGoToAnalysis = (code: string, name: string) => {
    navigate(`/stock?q=${encodeURIComponent(code + " " + name)}`);
  };

  let displayData = [...(result?.chipData || [])];

  // 过滤
  if (searchTerm) {
    displayData = displayData.filter(item => 
      item.name.includes(searchTerm) || item.code.includes(searchTerm)
    );
  }

  // 排序
  if (sortConfig) {
    displayData.sort((a, b) => {
      const aValue = a[sortConfig.key];
      const bValue = b[sortConfig.key];
      if (aValue === undefined || bValue === undefined) return 0;
      if (aValue < bValue) return sortConfig.direction === 'asc' ? -1 : 1;
      if (aValue > bValue) return sortConfig.direction === 'asc' ? 1 : -1;
      return 0;
    });
  }

  return (
    <div className="space-y-6 animate-fade-in max-w-7xl mx-auto pb-20">
      {/* Header Panel */}
      <div className="bg-slate-900 rounded-[2rem] shadow-2xl border border-slate-800 p-8 md:p-10 relative overflow-hidden text-white">
        <div className="relative z-10">
          <div className="flex flex-col md:flex-row justify-between items-start md:items-center gap-6">
            <div className="max-w-xl">
              <h2 className="text-3xl font-black flex items-center gap-4 mb-4">
                <div className="p-3 bg-indigo-600 rounded-2xl shadow-xl">
                  <Fingerprint className="w-8 h-8" />
                </div>
                创业板主力扫盘看板
              </h2>
              <p className="text-slate-400 text-sm font-medium leading-relaxed">
                实时扫描创业板（ChiNext）今日最强标的。透视主力【控盘分】与【核心成本】，为“龙头打板战法”提供高确定性过滤，识别强庄锁筹起爆点。
              </p>
            </div>
            <button 
              onClick={handleScan}
              disabled={loading}
              className="px-10 h-16 bg-white text-slate-900 rounded-[1.2rem] font-black shadow-xl hover:bg-slate-100 transition-all flex items-center gap-3 active:scale-[0.98] disabled:opacity-50"
            >
              {loading ? <Loader2 className="w-6 h-6 animate-spin" /> : <Zap className="w-6 h-6 text-amber-500 fill-amber-500" />}
              {loading ? `全网透视中 (${elapsed}s)` : '开始创业板扫盘'}
            </button>
          </div>
        </div>
        <div className="absolute right-0 top-0 w-1/3 h-full bg-gradient-to-l from-indigo-500/10 to-transparent pointer-events-none"></div>
      </div>

      {error && (
        <div className="p-6 bg-rose-50 border border-rose-100 rounded-2xl text-rose-700 flex items-center gap-4 shadow-sm animate-fade-in">
          <AlertTriangle className="w-6 h-6 shrink-0" />
          <span className="font-bold">{error}</span>
        </div>
      )}

      {loading && (
        <div className="py-24 text-center flex flex-col items-center justify-center bg-white rounded-[2.5rem] border border-dashed border-slate-200 animate-pulse">
          <Fingerprint className="w-16 h-16 text-indigo-300 mb-6" />
          <p className="text-slate-500 font-black text-xl tracking-tight">正在实时穿透创业板 L2 深度筹码数据与调研报告...</p>
          <p className="text-slate-400 text-sm mt-3 font-medium">AI 正在计算 20+ 只异动标的的成本峰值与控盘水位</p>
        </div>
      )}

      {!loading && result && (
        <div className="space-y-6 animate-slide-up">
          {/* Toolbar */}
          <div className="bg-white p-4 rounded-2xl border border-slate-200 flex flex-col md:flex-row gap-4 items-center justify-between shadow-sm">
             <div className="relative w-full md:w-80">
                <input 
