  onOpenSettings?: () => void;
}

export const HoldingsReview: React.FC<HoldingsReviewProps> = ({
  currentModel,
  currentMarket,
  settings,
  onOpenSettings
}) => {
  const [snapshot, setSnapshot] = useState<HoldingsSnapshot>({
    totalAssets: 0,
    positionRatio: 0, 
    date: new Date().toISOString().split('T')[0],
    holdings: []
  });

  const [journal, setJournal] = useState<JournalEntry[]>(() => {
    const saved = localStorage.getItem('qm_journal');
    if (!saved) return [];
    try {
      const parsed = JSON.parse(saved);
      return (Array.isArray(parsed) ? parsed : []).map(item => ({
        ...item,
        id: item.id || `legacy-${item.timestamp}-${Math.random().toString(36).substring(2, 9)}`
      }));
    } catch (e) {
      return [];
    }
  });

  const [tradingPlans, setTradingPlans] = useState<DailyTradingPlan[]>(() => {
    const saved = localStorage.getItem('qm_trading_plans');
    return saved ? JSON.parse(saved) : [];
  });

  const [analysisResult, setAnalysisResult] = useState<AnalysisResult | null>(null);
  const [loading, setLoading] = useState(false);
  const [parsing, setParsing] = useState(false);
  const [error, setError] = useState<string | null>(null);
  const [isHistoryOpen, setIsHistoryOpen] = useState(false);
  const [isPlanOpen, setIsPlanOpen] = useState(false);
  const [historyPage, setHistoryPage] = useState(1);
  const [activeTab, setActiveTab] = useState<'report' | 'charts' | 'periodic'>('report');
  const [periodicResult, setPeriodicResult] = useState<AnalysisResult | null>(null);
  const [editingIndex, setEditingIndex] = useState<number | null>(null);
  const [editForm, setEditForm] = useState<HoldingItemDetailed | null>(null);
  const [generatingPlan, setGeneratingPlan] = useState(false);

  const fileInputRef = useRef<HTMLInputElement>(null);
  const importInputRef = useRef<HTMLInputElement>(null);

  useEffect(() => {
    localStorage.setItem('qm_journal', JSON.stringify(journal));
  }, [journal]);

  useEffect(() => {
    localStorage.setItem('qm_trading_plans', JSON.stringify(tradingPlans));
  }, [tradingPlans]);

  const handleImageUpload = async (e: React.ChangeEvent<HTMLInputElement>) => {
    const file = e.target.files?.[0];
    if (!file) return;

    const apiKey = currentModel === ModelProvider.HUNYUAN_CN ? settings.hunyuanKey : settings.geminiKey;
    if (!apiKey) {
      setError("请先在设置中配置 API Key。");
      onOpenSettings?.();
      return;
    }

    setParsing(true);
    setError(null);

    try {
      const reader = new FileReader();
      reader.onloadend = async () => {
        const base64String = (reader.result as string).split(',')[1];
        try {
          let parsedData: HoldingsSnapshot;
          if (currentModel === ModelProvider.HUNYUAN_CN) {
             parsedData = await analyzeImageWithExternal(ModelProvider.HUNYUAN_CN, base64String, settings.hunyuanKey!);
          } else {
             parsedData = await parseBrokerageScreenshot(base64String, settings.geminiKey!);
          }
          const holdingsWithHorizon = parsedData.holdings.map(h => ({ ...h, horizon: 'medium' as const }));
          setSnapshot({
            ...parsedData,
            positionRatio: parsedData.positionRatio || 0, 
            holdings: holdingsWithHorizon,
            date: new Date().toISOString().split('T')[0] 
          });
        } catch (err: any) {
          setError(err.message || "识别失败，请重试或手动输入");
        } finally {
          setParsing(false);
        }
      };
      reader.readAsDataURL(file);
    } catch (err) {
      setParsing(false);
      setError("文件读取失败");
    }
  };

  const startEdit = (index: number, item: HoldingItemDetailed) => {
    setEditingIndex(index);
    setEditForm({ ...item, horizon: item.horizon || 'medium' });
  };

  const saveEdit = () => {
    if (editForm && editingIndex !== null) {
      const newHoldings = [...snapshot.holdings];
      if (!editForm.marketValue || editForm.marketValue === 0) {
        editForm.marketValue = editForm.volume * editForm.currentPrice;
      }
      newHoldings[editingIndex] = editForm;
      setSnapshot(prev => ({ ...prev, holdings: newHoldings }));
      setEditingIndex(null);
      setEditForm(null);
    }
  };

  const handleAnalyze = async () => {
    if (snapshot.holdings.length === 0) {
      setError("持仓列表为空，请先添加持仓");
      return;
    }
    setLoading(true);
    setAnalysisResult(null);
    setError(null);
    setActiveTab('report'); 

    const currentHoldingsText = snapshot.holdings.map((h, i) => {
      const marketVal = h.volume * h.currentPrice;
      return `${i+1}. ${h.name} (${h.code}): 持仓${h.volume}股, 成本${h.costPrice}, 现价${h.currentPrice}, 市值${marketVal.toFixed(2)}元`;
    }).join('\n');

    const prompt = `请作为专家复盘我的账户。持仓如下：\n${currentHoldingsText}\n总资产: ${snapshot.totalAssets}`;

    try {
      const result = await analyzeWithLLM(currentModel, prompt, true, settings, false, 'day', undefined, currentMarket);
      setAnalysisResult(result);
    } catch (err: any) {
      setError(err.message || "分析请求未能完成。");
    } finally {
      setLoading(false);
    }
  };

  const handleGeneratePlan = async () => {
    if (!analysisResult || !settings.geminiKey) return;
    setGeneratingPlan(true);
    try {
      const { items, summary } = await extractTradingPlan(analysisResult.content, settings.geminiKey);
      const newPlan: DailyTradingPlan = {
        id: crypto.randomUUID(),
        target_date: new Date(Date.now() + 86400000).toISOString().split('T')[0], 
        created_at: Date.now(),
        items: items,
        strategy_summary: summary
      };
      setTradingPlans(prev => [newPlan, ...prev]);
      setIsPlanOpen(true);
    } catch (err: any) {
      setError("生成交易计划失败: " + err.message);
    } finally {
      setGeneratingPlan(false);
    }
  };

  const handlePeriodicReview = async (period: 'week' | 'month' | 'all') => {
    if (journal.length < 1 || !settings.geminiKey) {
      setError("历史记录不足或未配置 API Key。");
      return;
    }
    setLoading(true);
    setPeriodicResult(null);
    setActiveTab('periodic');
    try {
      const result = await fetchPeriodicReview(journal, period, currentMarket, settings.geminiKey);
      setPeriodicResult(result);
    } catch (err: any) {
      setError(err.message);
    } finally {
      setLoading(false);
    }
  };

  const saveToJournal = () => {
    if (!analysisResult) return;
    const newEntry: JournalEntry = {
      id: crypto.randomUUID(),
      timestamp: Date.now(),
      snapshot: { ...snapshot },
      analysis: analysisResult,
      note: ""
    };
    setJournal(prev => [newEntry, ...prev]);
    alert("已保存到交易日志！");
  };

  const totalHistoryPages = Math.ceil(journal.length / HISTORY_PAGE_SIZE);
  const paginatedJournal = journal.slice((historyPage - 1) * HISTORY_PAGE_SIZE, historyPage * HISTORY_PAGE_SIZE);

  const getTrendData = () => {
    const history = journal.slice().reverse().map(entry => ({
      date: new Date(entry.timestamp).toLocaleDateString('zh-CN', {month: '2-digit', day: '2-digit'}),
      assets: entry.snapshot.totalAssets
    }));
    return history;
  };

  const renderPeriodicDashboard = (data: PeriodicReviewData) => (
    <div className="p-6 space-y-8 animate-fade-in">
      <div className="grid grid-cols-1 md:grid-cols-3 gap-6">
        <div className="bg-slate-900 rounded-xl p-6 text-white text-center">
          <h3 className="text-xs font-bold uppercase mb-2">综合表现评分</h3>
          <div className="text-4xl font-bold">{data.score}</div>
        </div>
        <div className="md:col-span-2 bg-slate-50 rounded-xl p-6">
          <h3 className="text-lg font-bold mb-2">市场大局解读</h3>
          <p className="text-sm text-slate-600 italic">{data.market_summary}</p>
        </div>
      </div>
      <div className="bg-white rounded-xl border p-6">
        <h3 className="text-lg font-bold mb-4">改进建议</h3>
        <ul className="space-y-2">
          {data.improvement_advice.map((advice, i) => (
            <li key={i} className="text-sm text-slate-700 flex gap-2">
              <Check className="w-4 h-4 text-emerald-500" /> {advice}
            </li>
          ))}
        </ul>
      </div>
    </div>
  );

  const renderReportContent = (content: string) => (
    <div className="p-6 space-y-6">
      {content.split('\n').map((line, i) => (
        <p key={i} className="text-slate-700 leading-relaxed">{line}</p>
      ))}
    </div>
  );

  return (
    <div className="space-y-6 animate-fade-in">
      <div className="bg-white rounded-xl shadow-sm border border-slate-200 p-6 no-print">
        <div className="flex flex-col md:flex-row justify-between items-start md:items-center gap-4 mb-6">
          <h2 className="text-xl font-bold text-slate-800 flex items-center gap-2">
            <UploadCloud className="w-6 h-6 text-indigo-600" /> 智能持仓复盘
          </h2>
          <div className="flex gap-2">
            <button onClick={() => setIsHistoryOpen(!isHistoryOpen)} className="px-3 py-2 bg-slate-100 rounded-lg text-sm"><History className="w-4 h-4"/></button>
            <input type="file" ref={fileInputRef} className="hidden" accept="image/*" onChange={handleImageUpload} />
            <button onClick={() => fileInputRef.current?.click()} className="px-4 py-2 bg-indigo-600 text-white rounded-lg font-medium flex items-center gap-2">
              {parsing ? <Loader2 className="w-4 h-4 animate-spin" /> : <Camera className="w-4 h-4" />} 识别截图
            </button>
          </div>
        </div>

        {isHistoryOpen && (
          <div className="mb-6 p-4 bg-slate-50 rounded-lg border">
            <h3 className="font-bold mb-4">历史日志</h3>
            <div className="space-y-2">
              {paginatedJournal.map(entry => (
                <div key={entry.id} onClick={() => { setSnapshot(entry.snapshot); setAnalysisResult(entry.analysis); setIsHistoryOpen(false); }} className="p-3 bg-white border rounded cursor-pointer hover:bg-indigo-50">
                  <div className="text-sm font-bold">{new Date(entry.timestamp).toLocaleString()}</div>
                  <div className="text-xs text-slate-500">资产: ¥{entry.snapshot.totalAssets.toLocaleString()}</div>
                </div>
              ))}
            </div>
          </div>
        )}

        {error && <div className="p-4 bg-red-50 text-red-700 rounded-lg mb-4 text-sm font-bold">{error}</div>}

        <div className="border rounded-lg overflow-hidden mb-6">
           <div className="bg-slate-50 p-4 border-b flex gap-6">
              <div><span className="text-xs font-bold text-slate-500 block">总资产</span><input type="number" value={snapshot.totalAssets} onChange={e => setSnapshot({...snapshot, totalAssets: parseFloat(e.target.value) || 0})} className="bg-transparent border-b font-bold w-28 outline-none"/></div>
              <div><span className="text-xs font-bold text-slate-500 block">仓位 %</span><input type="number" value={snapshot.positionRatio} onChange={e => setSnapshot({...snapshot, positionRatio: parseFloat(e.target.value) || 0})} className="bg-transparent border-b font-bold w-16 outline-none"/></div>
           </div>
           <table className="w-full text-sm text-left">
              <thead className="bg-slate-50 text-slate-500">
                <tr><th className="px-4 py-3">标的</th><th className="px-4 py-3">数量</th><th className="px-4 py-3">盈亏</th></tr>
              </thead>
              <tbody className="divide-y">
                {snapshot.holdings.map((h, i) => (
                  <tr key={i} className="hover:bg-slate-50">
                    <td className="px-4 py-3 font-bold">{h.name}</td>
                    <td className="px-4 py-3">{h.volume}</td>
                    <td className={`px-4 py-3 font-bold ${h.profit >= 0 ? 'text-red-500' : 'text-green-500'}`}>{h.profit}</td>
                  </tr>
                ))}
              </tbody>
           </table>
        </div>

        <div className="flex justify-end gap-3">
          <button onClick={() => handlePeriodicReview('week')} className="px-4 py-2 text-xs font-bold border rounded">近一周复盘</button>
          <button onClick={handleAnalyze} disabled={loading} className="px-6 py-2 bg-indigo-600 text-white rounded-lg font-bold">开始诊断</button>
        </div>
      </div>

      {(analysisResult || periodicResult) && (
        <div className="bg-white rounded-xl shadow-sm border overflow-hidden">
          <div className="bg-slate-50 px-6 py-4 flex gap-4">
            <button onClick={() => setActiveTab('report')} className={`px-4 py-2 text-sm font-bold ${activeTab === 'report' ? 'text-indigo-600' : 'text-slate-500'}`}>分析报告</button>
            <button onClick={() => setActiveTab('charts')} className={`px-4 py-2 text-sm font-bold ${activeTab === 'charts' ? 'text-indigo-600' : 'text-slate-500'}`}>图表趋势</button>
            <button onClick={saveToJournal} className="ml-auto px-4 py-2 bg-white border text-indigo-600 rounded-lg text-sm font-bold">保存日志</button>
          </div>
          <div className="bg-white">
            {activeTab === 'report' && analysisResult && renderReportContent(analysisResult.content)}
            {activeTab === 'periodic' && periodicResult?.periodicData && renderPeriodicDashboard(periodicResult.periodicData)}
            {activeTab === 'charts' && (
              <div className="p-6 h-72">
                <ResponsiveContainer width="100%" height="100%">
                  <LineChart data={getTrendData()}>
                    <CartesianGrid strokeDasharray="3 3" />
                    <XAxis dataKey="date" />
                    <YAxis />
                    <Tooltip />
                    <Line type="monotone" dataKey="assets" stroke="#3b82f6" />
                  </LineChart>
                </ResponsiveContainer>
              </div>
            )}
          </div>
        </div>
      )}
    </div>
  );
};
